function uuidv4() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function (c) {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}
function headerValue(headers, name) {
  const target = name.toLowerCase();
  for (const [key, value] of Object.entries(headers || {})) {
    if (String(key).toLowerCase() === target) return Array.isArray(value) ? value[0] : value;
  }
  return '';
}
function parseStripeSignature(header) {
  const out = { t: null, v1: [] };
  for (const part of String(header || '').split(',')) {
    const idx = part.indexOf('=');
    if (idx === -1) continue;
    const key = part.slice(0, idx).trim();
    const value = part.slice(idx + 1).trim();
    if (key === 't') out.t = value;
    if (key === 'v1') out.v1.push(value);
  }
  return out;
}
function hex(buffer) {
  return Array.from(new Uint8Array(buffer)).map((b) => b.toString(16).padStart(2, '0')).join('');
}
function constantTimeEqual(a, b) {
  const left = String(a || '').toLowerCase();
  const right = String(b || '').toLowerCase();
  let diff = left.length ^ right.length;
  const max = Math.max(left.length, right.length);
  for (let i = 0; i < max; i++) diff |= (left.charCodeAt(i) || 0) ^ (right.charCodeAt(i) || 0);
  return diff === 0;
}
async function hmacSha256Hex(secret, payload) {
  const nodeCrypto = require('crypto');
  return nodeCrypto.createHmac('sha256', secret).update(payload).digest('hex');
}
async function verifyStripe(root, replay) {
  const response_required = !!root.headers && !replay;
  if (!response_required) return { response_required, authorized: true, auth_error: null, rawPayload: null };
  const secret = $env.STRIPE_WEBHOOK_SECRET || '';
  if (!secret) return { response_required, authorized: false, auth_error: 'missing STRIPE_WEBHOOK_SECRET', rawPayload: null };
  const signature = headerValue(root.headers, 'stripe-signature');
  if (!signature) return { response_required, authorized: false, auth_error: 'missing Stripe-Signature header', rawPayload: null };
  const binary = $input.first().binary && $input.first().binary.data && $input.first().binary.data.data;
  const rawPayload = binary ? Buffer.from(binary, 'base64').toString('utf8') : (typeof root.body === 'string' ? root.body : JSON.stringify(root.body || {}));
  const parsed = parseStripeSignature(signature);
  if (!parsed.t || parsed.v1.length === 0) return { response_required, authorized: false, auth_error: 'malformed Stripe-Signature header', rawPayload };
  const tolerance = Number($env.STRIPE_WEBHOOK_TOLERANCE_SECONDS || 300);
  const timestamp = Number(parsed.t);
  if (!Number.isFinite(timestamp)) return { response_required, authorized: false, auth_error: 'invalid Stripe-Signature timestamp', rawPayload };
  if (Number.isFinite(tolerance) && tolerance > 0 && Math.abs(Math.floor(Date.now() / 1000) - timestamp) > tolerance) {
    return { response_required, authorized: false, auth_error: 'expired Stripe-Signature timestamp', rawPayload };
  }
  const expected = await hmacSha256Hex(secret, parsed.t + '.' + rawPayload);
  const authorized = parsed.v1.some((sig) => constantTimeEqual(sig, expected));
  return { response_required, authorized, auth_error: authorized ? null : 'invalid Stripe-Signature digest', rawPayload };
}

// --- Ingress: verify Stripe signature, normalize body, derive correlation id + idempotency key ---
// Accepts both the manual demo body and a Stripe invoice.payment_failed event.
const root = $input.first().json || {};
const replay = !!root.replay;
const verification = await verifyStripe(root, replay);
let body = root.body || root;
if (verification.rawPayload) {
  try {
    body = JSON.parse(verification.rawPayload);
  } catch (e) {
    verification.authorized = false;
    verification.auth_error = 'invalid JSON payload';
    body = {};
  }
}
// Stripe shape: { type: 'invoice.payment_failed', data: { object: {...} } }
const stripeObj = (body.data && body.data.object) || {};

const tenant_id = body.tenant_id || stripeObj.client_reference_id || root.tenant_id || null;
const email = body.email || stripeObj.customer_email || stripeObj.customer_details?.email || '';
const tenant_name = body.tenant_name || body.name || stripeObj.customer_details?.name || 'Unknown Tenant';
const source = body.source || (body.type ? 'stripe' : 'manual');

// Lead-owned idempotency key derivation: stable source id, NEVER random (Contract G).
// Prefer the Stripe event id (unique per failed-payment attempt). If absent (manual
// demo), fall back to a STABLE composite of the invoice + attempt so retries of the
// same failed invoice dedupe correctly. No Date.now()/random - that would defeat dedup.
const event_id = body.event_id || body.id || stripeObj.id || null;
const stripe_invoice_id_early = stripeObj.id || body.stripe_invoice_id || null;
const attempt_early = stripeObj.attempt_count != null ? Number(stripeObj.attempt_count) : (body.attempt || 1);
const idem_key = 'dunning:' + (event_id || (tenant_id + ':' + (stripe_invoice_id_early || 'noinv') + ':' + attempt_early));

// Contract B replay: 05-dlq-replay re-enters via the Execute Workflow Trigger with
// {body: <original trigger>, correlation_id, tenant_id, replay:true}. Preserve the
// original correlation_id and mark the run so it bypasses the idempotency gate.
const src = replay ? 'replay' : source;

// correlation_id must be a valid uuid (audit_log.correlation_id is uuid not null).
// On replay, reuse the original correlation_id so the failure, the redrive, and the
// re-run all thread onto one correlation-ID search.
const correlation_id = (replay && root.correlation_id) ? root.correlation_id : uuidv4();

return [{
  json: {
    tenant_id,
    tenant_name,
    email,
    source: src,
    event_id,
    idem_key, correlation_id,
    replay,
    response_required: verification.response_required,
    authorized: verification.authorized,
    auth_error: verification.auth_error,
    execution_id: String($execution.id),
    supabase_url: ($env.SUPABASE_URL || '').replace(/\/$/, ''),
    service_key: $env.SUPABASE_SERVICE_KEY || '',
    // Stripe invoice fields we need
    stripe_invoice_id: stripeObj.id || body.stripe_invoice_id || null,
    amount_usd: stripeObj.amount_due != null ? Number(stripeObj.amount_due) / 100 : (body.amount_usd || 0),
    attempt: stripeObj.attempt_count != null ? Number(stripeObj.attempt_count) : (body.attempt || 1),
    customer_email: stripeObj.customer_email || body.customer_email || email,
    // For manual demo: allow overriding
    invoice_status: body.invoice_status || (stripeObj.status || 'payment_failed')
  }
}];

// Shape {key, tenant_id} for the 02-idempotency-check sub-workflow (Contract G2).
const p = $('Gen Correlation + Normalize').first().json;
if (!p.tenant_id) {
  throw new Error('dunning: missing tenant_id (required for provisioning)');
}
return [{ json: { key: p.idem_key, tenant_id: p.tenant_id, workflow: '06-billing-dunning' } }];

const p = $('Gen Correlation + Normalize').first().json;
return [{ json: {
  tenant_id: p.tenant_id,
  correlation_id: p.correlation_id,
  service: 'dunning',
  step: 'ingest',
  status: 'skipped',
  payload: { reason: 'duplicate event', key: $('Idempotency Check').first().json.key, via: 'contract-g' }
} }];

const p = $('Gen Correlation + Normalize').first().json;
return [{ json: {
  tenant_id: p.tenant_id,
  correlation_id: p.correlation_id,
  service: 'dunning',
  step: 'ingest',
  status: 'started',
  payload: { source: p.source, execution_id: p.execution_id, amount_usd: p.amount_usd, stripe_invoice_id: p.stripe_invoice_id, attempt: p.attempt }
} }];

