// Determine if this attempt exceeds policy max -> escalate to suspended.
const p = $('Gen Correlation + Normalize').first().json;
const pol = $('Resolve Policy').first().json;
const maxAttempts = (pol.policy && pol.policy.retry && pol.policy.retry.max_attempts) || 3;
const currentAttempt = p.attempt || 1;
const isFinal = currentAttempt >= maxAttempts;
return [{ json: { isFinal, maxAttempts, currentAttempt, policy: pol.policy } }];

