// Resolve the health-score penalty from tenant policy (default 10 per failed payment).
// The next nodes fetch the current score, subtract this, and PATCH the numeric result
// (PostgREST can't evaluate a SQL expression like GREATEST() in a JSON body).
// NOTE: fetch-then-patch is not atomic; acceptable because dunning events per tenant
// are rare and serialized. A future hardening would move this to an atomic RPC.
const p = $('Gen Correlation + Normalize').first().json;
const pol = $('Resolve Policy').first().json;
const penalty = (pol.policy && pol.policy.retry && pol.policy.retry.health_penalty) || 10;
return [{ json: { penalty, tenant_id: p.tenant_id, correlation_id: p.correlation_id } }];

// Compute new health_score and patch.
const p = $('Gen Correlation + Normalize').first().json;
const penalty = $('Compute Health Penalty').item.json.penalty;
const healthRows = $('Fetch Current Health').item.json;
const current = (Array.isArray(healthRows) ? healthRows[0] : healthRows)?.health_score || 100;
const newScore = Math.max(0, current - penalty);
return [{ json: { new_health_score: newScore, penalty, tenant_id: p.tenant_id } }];

// Notify finance + CSM via Telegram (Code node, non-throwing; mirrors G1 pattern).
const p = $('Gen Correlation + Normalize').first().json;
const esc = $('Check Escalation?').first().json;
const text = [
  esc.isFinal ? '🚨 *Dunning escalation: tenant suspended*' : '💸 *Dunning event: payment failed*',
  'Tenant: ' + (p.tenant_name || 'unknown') + ' (' + (p.tenant_id || 'n/a') + ')',
  'Invoice: ' + (p.stripe_invoice_id || 'n/a') + '  |  Amount: $' + (p.amount_usd || 0),
  'Attempt: ' + (p.attempt || 1) + ' / ' + (esc.maxAttempts || 3),
  esc.isFinal ? 'Status: SUSPENDED' : 'Status: ACTIVE (retrying)',
  'Correlation: `' + (p.correlation_id || 'n/a') + '`'
].join('\n');

let alert_delivered = false;
let notice = null;
const token = $env.TELEGRAM_BOT_TOKEN;
const chat = $env.TELEGRAM_CHAT_ID;

if (token && chat) {
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.telegram.org/bot' + token + '/sendMessage',
      body: { chat_id: chat, text: text, parse_mode: 'Markdown' },
      json: true
    });
    alert_delivered = true;
  } catch (e) {
    notice = 'telegram failed: ' + (e && e.message ? e.message : String(e));
  }
} else {
  notice = 'telegram skipped: TELEGRAM_BOT_TOKEN / TELEGRAM_CHAT_ID not set';
}

return [{ json: { alert_delivered, notice, escalated: esc.isFinal } }];

const p = $('Gen Correlation + Normalize').first().json;
const esc = $('Check Escalation?').first().json;
return [{ json: {
  tenant_id: p.tenant_id,
  correlation_id: p.correlation_id,
  service: 'dunning',
  step: 'complete',
  status: 'success',
  payload: { invoice_id: p.stripe_invoice_id, attempt: p.attempt, escalated: esc.isFinal, health_penalty: $('Compute Health Penalty').item.json.penalty, telegram_delivered: $('Notify Telegram').item.json.alert_delivered }
} }];
